/// Token utilities matching TypeScript Anchor SDK utils.token////// Provides SPL Token program utilities with exact compatibility/// to the TypeScript Anchor SDK's utils.token module./// /// Uses espresso-cash-public packages for proven, battle-tested implementations.library;// Core dart-coral-xyz types for API compatibilityimport '../types/public_key.dart';// Leverage espresso-cash-public SPL Token infrastructureimport 'package:solana/solana.dart' as solana;// Export espresso-cash-public token utilities for direct useexport 'package:solana/src/programs/token_program/program.dart' show TokenProgram, Token2022Program;export 'package:solana/src/programs/associated_token_account_program/program.dart' show AssociatedTokenAccountProgram;export 'package:solana/src/programs/token_program/instruction.dart' show TokenInstruction;export 'package:solana/src/programs/associated_token_account_program/instruction.dart' show AssociatedTokenAccountInstruction;/// Token program utilities////// Matches TypeScript: utils.token.*/// Leverages espresso-cash-public for proven SPL Token implementationsclass TokenUtils {  /// SPL Token Program ID  ///  /// Matches TypeScript: utils.token.TOKEN_PROGRAM_ID  static PublicKey get TOKEN_PROGRAM_ID =>       PublicKey.fromBase58(solana.TokenProgram.id.toBase58());  /// SPL Associated Token Account Program ID  ///  /// Matches TypeScript: utils.token.ASSOCIATED_PROGRAM_ID  static PublicKey get ASSOCIATED_PROGRAM_ID =>       PublicKey.fromBase58(solana.AssociatedTokenAccountProgram.id.toBase58());  /// Find the associated token address for owner and mint  ///  /// Matches TypeScript: utils.token.associatedAddress({mint, owner})  /// Uses espresso-cash-public's proven implementation  static Future<PublicKey> associatedAddress({    required PublicKey mint,    required PublicKey owner,  }) async {    final espressoMint = solana.Ed25519HDPublicKey.fromBase58(mint.toBase58());    final espressoOwner = solana.Ed25519HDPublicKey.fromBase58(owner.toBase58());        final associatedTokenAddress = await solana.findAssociatedTokenAddress(      owner: espressoOwner,      mint: espressoMint,    );        return PublicKey.fromBase58(associatedTokenAddress.toBase58());  }  /// Create associated token account instruction using espresso-cash-public  ///  /// Uses espresso-cash-public's proven instruction builders  static Future<solana.AssociatedTokenAccountInstruction> createAssociatedTokenAccountInstruction({    required PublicKey mint,    required PublicKey owner,    required PublicKey funder,  }) async {    final espressoMint = solana.Ed25519HDPublicKey.fromBase58(mint.toBase58());    final espressoOwner = solana.Ed25519HDPublicKey.fromBase58(owner.toBase58());    final espressoFunder = solana.Ed25519HDPublicKey.fromBase58(funder.toBase58());        final address = await associatedAddress(mint: mint, owner: owner);    final espressoAddress = solana.Ed25519HDPublicKey.fromBase58(address.toBase58());        return solana.AssociatedTokenAccountInstruction.createAccount(      mint: espressoMint,      owner: espressoOwner,      funder: espressoFunder,      address: espressoAddress,    );  }  /// Create a token transfer instruction  ///  /// Uses espresso-cash-public's proven instruction builders  static solana.TokenInstruction createTransferInstruction({    required PublicKey source,    required PublicKey destination,     required PublicKey owner,    required int amount,  }) {    final espressoSource = solana.Ed25519HDPublicKey.fromBase58(source.toBase58());    final espressoDestination = solana.Ed25519HDPublicKey.fromBase58(destination.toBase58());    final espressoOwner = solana.Ed25519HDPublicKey.fromBase58(owner.toBase58());        return solana.TokenInstruction.transfer(      source: espressoSource,      destination: espressoDestination,      owner: espressoOwner,      amount: amount,    );  }  /// Create a mint tokens instruction  ///  /// Uses espresso-cash-public's proven instruction builders  static solana.TokenInstruction createMintToInstruction({    required PublicKey mint,    required PublicKey destination,    required PublicKey authority,    required int amount,  }) {    final espressoMint = solana.Ed25519HDPublicKey.fromBase58(mint.toBase58());    final espressoDestination = solana.Ed25519HDPublicKey.fromBase58(destination.toBase58());    final espressoAuthority = solana.Ed25519HDPublicKey.fromBase58(authority.toBase58());        return solana.TokenInstruction.mintTo(      mint: espressoMint,      destination: espressoDestination,      authority: espressoAuthority,      amount: amount,    );  }}// Export the main utilities for convenienceexport 'package:solana/src/helpers.dart' show findAssociatedTokenAddress;
